  { applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, rate: LOYALTY_RATE },
  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE },
];

